import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"启动游戏","description":"了解如何利用各种启动配置文件在实时游戏环境中启动和调试你的模组。","frontmatter":{"title":"启动游戏","description":"了解如何利用各种启动配置文件在实时游戏环境中启动和调试你的模组。","authors":["IMB11","Tenneb22"],"files":[]},"headers":[],"relativePath":"zh_cn/1.21.10/develop/getting-started/launching-the-game.md","filePath":"versions/1.21.10/translated/zh_cn/develop/getting-started/launching-the-game.md","lastUpdated":1766682904000}`);var c={name:`zh_cn/1.21.10/develop/getting-started/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">启动游戏 <a class="header-anchor" href="#h1" aria-label="Permalink to “启动游戏”">​</a></h1><p>Fabric Loom 提供了各种启动配置文件，可以帮助你在实时游戏环境中启动以及调试你的模组。 本指南将介绍各种启动配置文件以及如何用它们来调试和在游戏中测试你的模组。</p><h2 id="launch-profiles" tabindex="-1">启动配置文件 <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “启动配置文件”">​</a></h2><p>如果在使用 IntelliJ IDEA，那么可以从窗口右上角找到启动配置文件。 单击下拉菜单可以查看可用的启动配置文件。</p><p>应该有一个客户端和服务器配置文件，可以选择正常运行或在调试模式下运行它：</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="启动配置文件" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Gradle 任务 <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Gradle 任务”">​</a></h2><p>如果使用的是命令行，则可以使用以下 Gradle 命令启动游戏：</p><ul><li><code>./gradlew runClient</code> - 以客户端模式启动游戏。</li><li><code>./gradlew runServer</code> - 以服务器模式启动游戏。</li></ul><p>这种方法的唯一问题是无法轻松调试代码。 如果要调试代码，则需要使用 IntelliJ IDEA 中的启动配置文件或通过你所使用的 IDE 中的 Gradle 集成。</p><h2 id="hotswapping-classes" tabindex="-1">热交换类 <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “热交换类”">​</a></h2><p>在调试模式下运行游戏时，可以热交换你的类而无需重启游戏。 这对于快速测试代码的更改很有用。</p><p>但你仍然受到很大限制：</p><ul><li>你无法添加或移除方法</li><li>你无法更改方法参数</li><li>你无法添加或移除字段</li></ul><p>但是，通过使用 <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">JetBrains Runtime</a>，你可以绕过大部分限制，甚至可以添加或删除类和方法。 这样大多数更改无需重启游戏即可生效。</p><p>不要忘记在 Minecraft 运行配置中的 VM 参数选项中添加以下内容：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">热交换 Mixin <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “热交换 Mixin”">​</a></h2><p>如果正在使用 Mixin，则可以热交换 Mixin 类而无需重启游戏。 这对于快速测试 Mixin 的更改很有用。</p><p>但是你需要安装 Mixin Java 代理才能使其正常工作。</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. 找到 Mixin 库 Jar <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. 找到 Mixin 库 Jar”">​</a></h3><p>在 IntelliJ IDEA 中，你可以在“项目”部分的“外部库”部分中找到 mixin 库 jar：</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Mixin 库" loading="lazy"></p><p>你需要复制 jar 的“绝对路径”以供下一步使用。</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. 添加 <code>-javaagent</code> VM 参数 <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. 添加 -javaagent VM 参数”">​</a></h3><p>在你的“Minecraft 客户端”和/或“Minecraft 服务器”运行配置中，将以下内容添加到 VM 参数选项：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;此处为 mixin 库 jar 的路径&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="VM 参数屏幕截图" loading="lazy"></p><p>现在，你应该能够在调试期间修改 mixin 方法的内容，并且无需重启游戏即可使更改生效。</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};